                      )}
                  </div>

                  {/* Products List */}
                  <div className="bg-gray-50 dark:bg-black/20 rounded-[14px] p-3 border border-gray-200 dark:border-white/5 mb-4">
                      <div className="flex justify-between items-center mb-2">
