    setActiveIndex((prev) => (prev + 1) % services.length);
  }, [services.length]);

  const prevSlide = useCallback(() => {
    setActiveIndex((prev) => (prev - 1 + services.length) % services.length);
  }, [services.length]);

  useEffect(() => {
    if (isPaused) return;
    const timer = setInterval(nextSlide, 5000);
    return () => clearInterval(timer);
  }, [nextSlide, isPaused]);

  return (
    <>
      <Section id="rf-main-services" className="relative overflow-hidden py-10">
        <SectionHeader 
          title={t('services_title')} 
          subtitle="اكتشف حلولنا المالية المتكاملة المصممة لخدمتك"
        />

        {/* Slider Container */}
        <div 
          className="relative w-full h-[320px] mt-6 group"
          onMouseEnter={() => setIsPaused(true)}
          onMouseLeave={() => setIsPaused(false)}
        >
          {/* Cards Frame */}
          <div className="relative w-full h-full flex items-center justify-center">
            {services.map((service, index) => {
              const isCenter = index === activeIndex;
              const isPrev = index === (activeIndex - 1 + services.length) % services.length;
              const isNext = index === (activeIndex + 1) % services.length;

              let positionClass = "opacity-0 scale-75 translate-x-0 pointer-events-none";
              if (isCenter) positionClass = "opacity-100 scale-100 z-30 translate-x-0 shadow-2xl";
              if (isPrev) positionClass = `opacity-40 scale-90 z-20 ${direction === 'rtl' ? 'translate-x-[60%] sm:translate-x-[40%]' : '-translate-x-[60%] sm:-translate-x-[40%] pointer-events-none'}`;
              if (isNext) positionClass = `opacity-40 scale-90 z-20 ${direction === 'rtl' ? '-translate-x-[60%] sm:-translate-x-[40%]' : 'translate-x-[60%] sm:translate-x-[40%]'}`;

              return (
                <div 
                  key={index}
                  onClick={() => isCenter ? setSelectedService(service) : setActiveIndex(index)}
                  className={`absolute w-full max-w-[290px] h-[260px] transition-all duration-700 ease-out cursor-pointer ${positionClass}`}
                >
                  <div className={`w-full h-full bg-white dark:bg-[#12031a] rounded-[28px] border-2 ${isCenter ? 'border-gold shadow-gold/20' : 'border-gold/20'} p-6 flex flex-col justify-between overflow-hidden relative group/card`}>

                    <div className="absolute -top-12 -right-12 w-24 h-24 bg-gold/5 rounded-full blur-2xl group-hover/card:bg-gold/10 transition-colors" />
                    <div className="absolute bottom-0 right-0 w-full h-1 bg-gold/10 overflow-hidden">
                       <div className={`h-full bg-gold-gradient transition-all ease-linear ${isCenter && !isPaused ? 'w-full duration-[5000ms]' : 'w-0 duration-0'}`} />
                    </div>

                    <div>
                      <div className="flex justify-between items-start mb-3">
                        <span className="text-[10px] font-bold text-gold bg-gold/5 px-2 py-1 rounded-full border border-gold/10">
                          {service.tags}
                        </span>
                        {isCenter && <Sparkles size={16} className="text-gold animate-pulse" />}
                      </div>
                      <h3 className={`text-[16px] font-extrabold text-brand dark:text-white mb-2 transition-transform duration-500 ${isCenter ? 'translate-y-0' : 'translate-y-2'}`}>
                        {service.name}
                      </h3>
                      <p className={`text-[12px] text-muted dark:text-gray-400 leading-relaxed line-clamp-3 transition-opacity duration-700 ${isCenter ? 'opacity-100' : 'opacity-40'}`}>
                        {service.description}
                      </p>
                    </div>

                    <div className="mt-auto">
                      <button className={`flex items-center gap-2 text-[11px] font-bold text-brand dark:text-gold hover:text-gold transition-all ${isCenter ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'}`}>
                        {t('know_more')}
                        {direction === 'rtl' ? <ArrowLeft size={12} /> : <ArrowRight size={12} />}
                      </button>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>

          <button onClick={(e) => { e.stopPropagation(); prevSlide(); }} className="absolute top-1/2 -right-2 sm:right-4 -translate-y-1/2 w-10 h-10 rounded-full bg-white/80 dark:bg-brand/80 backdrop-blur-md border border-gold/30 flex items-center justify-center text-brand dark:text-gold shadow-lg z-40 hover:bg-gold hover:text-brand transition-all active:scale-90">
            {direction === 'rtl' ? <ChevronRight size={22} /> : <ChevronLeft size={22} />}
          </button>
          <button onClick={(e) => { e.stopPropagation(); nextSlide(); }} className="absolute top-1/2 -left-2 sm:left-4 -translate-y-1/2 w-10 h-10 rounded-full bg-white/80 dark:bg-brand/80 backdrop-blur-md border border-gold/30 flex items-center justify-center text-brand dark:text-gold shadow-lg z-40 hover:bg-gold hover:text-brand transition-all active:scale-90">
            {direction === 'rtl' ? <ChevronLeft size={22} /> : <ChevronRight size={22} />}
          </button>
        </div>

        <div className="flex justify-center gap-2 mt-4 z-20 relative">
          {services.map((_, i) => (
            <button key={i} onClick={() => setActiveIndex(i)} className={`transition-all duration-500 rounded-full ${activeIndex === i ? 'w-8 h-1.5 bg-gold' : 'w-1.5 h-1.5 bg-gold/30'}`} />
          ))}
        </div>
      </Section>

      {selectedService && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 animate-in fade-in duration-300">
           <div className="absolute inset-0 bg-brand/60 backdrop-blur-sm" onClick={() => setSelectedService(null)} />
           <div className="relative w-full max-w-[380px] bg-white dark:bg-[#1a0b25] rounded-[24px] border border-gold/50 shadow-2xl p-6 animate-in zoom-in-95 duration-200">
              <button onClick={() => setSelectedService(null)} className={`absolute top-4 ${direction === 'rtl' ? 'left-4' : 'right-4'} w-8 h-8 rounded-full bg-gray-50 dark:bg-white/10 text-muted flex items-center justify-center hover:bg-gray-100 transition-colors`}>
                <X size={18} />
              </button>
              <div className="pt-2">
                <div className="text-[11px] font-bold text-gold mb-2 flex items-center gap-2">
                  <span className="w-2 h-2 rounded-full bg-gold"></span>
                  {selectedService.tags}
                </div>
                <h3 className="text-[20px] font-extrabold text-brand dark:text-white mb-4">{selectedService.name}</h3>
                <div className="bg-gray-50 dark:bg-black/20 rounded-xl p-4 border border-gray-100 dark:border-white/10 mb-6">
                  <p className={`text-[13px] text-muted dark:text-gray-300 leading-7 ${direction === 'rtl' ? 'text-right' : 'text-left'}`}>{selectedService.description}</p>
                </div>
              </div>
              <a href={selectedService.link} onClick={() => setSelectedService(null)} className="block">
                <Button className="w-full h-11 text-[13px] gap-2 !justify-between px-6">
                  <span>{t('goto_service')}</span>
                  <ArrowLeft size={16} />
                </Button>
              </a>
           </div>
        </div>
      )}
    </>
  );
};

