import React, { useState, useEffect } from 'react';
import { Menu, User, Sun, Moon } from 'lucide-react';
import SideMenu from './SideMenu';
import AuthModal from './AuthModal';
import CustomerDashboard from './CustomerDashboard';
import { UserProfile } from '../types';
import { useLanguage } from '../contexts/LanguageContext';
import Logo from './Logo';

const Header: React.FC = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [showDashboard, setShowDashboard] = useState(false);
  const [user, setUser] = useState<UserProfile | null>(null);
  const { t, toggleLanguage, language } = useLanguage();
  const [isDark, setIsDark] = useState(false);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);

    const savedTheme = localStorage.getItem('theme');
    if (savedTheme === 'dark') {
      setIsDark(true);
      document.documentElement.classList.add('dark');
    }

    const currentFileStr = localStorage.getItem('currentFile');
    if (currentFileStr) {
      try { setUser(JSON.parse(currentFileStr)); } catch (e) {}
    }
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleLogin = (loggedInUser: UserProfile) => {
    setUser(loggedInUser);
    setShowAuthModal(false);
    setShowDashboard(true);
  };

  const handleLogout = () => {
    setUser(null);
    setShowDashboard(false);
    localStorage.removeItem('currentFile');
  };

  const toggleTheme = () => {
    const nextTheme = !isDark;
    setIsDark(nextTheme);
    document.documentElement.classList.toggle('dark');
    localStorage.setItem('theme', nextTheme ? 'dark' : 'light');
  };

  return (
    <>
      <header className={`fixed top-0 left-0 right-0 z-50 flex items-center justify-center h-[70px] px-4 transition-all duration-500 
        ${isScrolled ? 'backdrop-blur-md bg-white/60 dark:bg-black/40 border-b border-white/20 shadow-sm' : 'bg-transparent'}`}>
        <div className="w-full max-w-[520px] h-full flex items-center justify-between relative">

          <div className="z-20">
             {user ? (
               <button onClick={() => setShowDashboard(true)} className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[11px] font-bold transition-all ${isScrolled ? 'bg-brand/10 text-brand dark:text-white' : 'bg-white/20 text-white'}`}>
                 <div className="w-5 h-5 rounded-full bg-gold flex items-center justify-center text-brand"><User size={12} /></div>
                 <span>{t('my_profile')}</span>
               </button>
             ) : (
               <button onClick={() => setShowAuthModal(true)} className={`px-3 py-1.5 rounded-full text-[10px] font-bold ${isScrolled ? 'bg-brand text-gold' : 'bg-white text-brand shadow-lg'}`}>
                 {t('login_register')}
               </button>
             )}
          </div>

          <a href="/" onClick={(e) => { e.preventDefault(); window.scrollTo({top:0, behavior:'smooth'}); }} className="absolute left-1/2 -translate-x-1/2 z-10">
            <Logo className="h-8" variant={isScrolled ? 'default' : 'white'} />
          </a>

          <div className="flex items-center gap-1.5 z-20">
            <button onClick={toggleLanguage} className={`w-8 h-8 rounded-full font-bold text-[10px] ${isScrolled ? 'text-brand dark:text-gold' : 'text-white'}`}>
              {language === 'ar' ? 'EN' : 'ع'}
            </button>
            <button onClick={toggleTheme} className={`p-2 rounded-full ${isScrolled ? 'text-brand dark:text-gold' : 'text-white'}`}>
              {isDark ? <Sun size={20} /> : <Moon size={20} />}
            </button>
            <button onClick={() => setIsMenuOpen(true)} className={`p-2 rounded-full ${isScrolled ? 'text-brand dark:text-gold' : 'text-white'}`}>
              <Menu size={26} />
            </button>
          </div>
        </div>
      </header>

      <SideMenu isOpen={isMenuOpen} onClose={() => setIsMenuOpen(false)} />
      {showAuthModal && <AuthModal onClose={() => setShowAuthModal(false)} onLogin={handleLogin} />}
      {showDashboard && user && <CustomerDashboard user={user} onClose={() => setShowDashboard(false)} onLogout={handleLogout} />}
    </>
  );
};

export default Header;

