const SideMenu: React.FC<SideMenuProps> = ({ isOpen, onClose }) => {
  const [shouldRender, setShouldRender] = useState(isOpen);

  useEffect(() => {
    if (isOpen) {
      setShouldRender(true);
      document.body.style.overflow = 'hidden';
    } else {
      const timer = setTimeout(() => setShouldRender(false), 300);
      document.body.style.overflow = 'unset';
      return () => clearTimeout(timer);
    }
    return () => { document.body.style.overflow = 'unset'; };
  }, [isOpen]);

  const handleLinkClick = (e: React.MouseEvent<HTMLAnchorElement>, href: string) => {
    if (href.startsWith('#')) {
      if (href.includes('/')) {
        onClose();
      } else {
        e.preventDefault();
        onClose();
        setTimeout(() => {
          if (href === '#/') {
             window.scrollTo({ top: 0, behavior: 'smooth' });
             window.history.pushState("", document.title, window.location.pathname);
          } else {
             const targetId = href.replace('#', '');
             const element = document.getElementById(targetId);
             if (element) {
               element.scrollIntoView({ behavior: 'smooth', block: 'start' });
               window.history.pushState(null, '', href);
             }
          }
        }, 100);
      }
    } else {
       onClose();
    }
  };

  if (!shouldRender) return null;

  return (
    <div className={`fixed inset-0 z-[100] flex justify-end transition-opacity duration-300 ${isOpen ? 'opacity-100' : 'opacity-0'}`}>
      <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={onClose} />
      <div className={`relative w-full max-w-[320px] h-full bg-white dark:bg-[#12031a] shadow-2xl flex flex-col transition-transform duration-300 ease-in-out ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="flex items-center justify-between p-5 border-b border-gold/10">
           <button onClick={onClose} className="w-8 h-8 flex items-center justify-center text-muted hover:text-brand hover:bg-gray-50 dark:hover:bg-white/10 rounded-full transition-colors">
             <X size={24} />
           </button>
           <div className="flex-1 flex justify-center mr-[-32px]">
             <Logo className="h-10" />
           </div>
        </div>
        <div className="flex-1 overflow-y-auto py-2">
            {menuItems.map((item, idx) => (
                <a 
                  key={idx} 
                  href={item.href} 
                  onClick={(e) => handleLinkClick(e, item.href)}
                  className={`block px-6 py-4 text-[14px] font-bold border-b border-gray-50 dark:border-white/5 transition-colors text-right
                    ${item.highlight 
                      ? 'text-gold bg-[#FFFBF2] dark:bg-gold/5 border-l-4 border-l-gold' 
                      : 'text-brand dark:text-white hover:bg-[#FFFBF2] dark:hover:bg-gold/5'
                    }`}
                >
                    {item.label}
                </a>
            ))}
        </div>
        <div className="p-6 bg-[#F9F8FC] dark:bg-black border-t border-gold/20 flex flex-col items-center">
            <div className="text-[15px] font-extrabold text-brand dark:text-gold mb-4">ريفانس المالية</div>
            <div className="flex items-center gap-5">
                {socialLinks.map((link, i) => (
                    <a key={i} href={link.href} target="_blank" rel="noopener noreferrer" className="opacity-60 hover:opacity-100 hover:scale-110 transition-all">
                        <img src={link.icon} alt={link.label} className="w-5 h-5 object-contain" />
                    </a>
                ))}
            </div>
        </div>
      </div>
    </div>
  );
};

