               <button onClick={() => setShowAuthModal(true)} className={`px-2.5 py-1 rounded-full text-[9px] font-bold ${isScrolled ? 'bg-brand text-gold' : 'bg-white text-brand shadow-lg'}`}>
                 {t('login_register')}
               </button>
             )}
