import React, { useState, useEffect } from 'react';
import { Menu, User, Sun, Moon } from 'lucide-react';
import SideMenu from './SideMenu';
import AuthModal from './AuthModal';
import CustomerDashboard from './CustomerDashboard';
import { UserProfile } from '../types';
import { useLanguage } from '../contexts/LanguageContext';
import Logo from './Logo';

const Header: React.FC = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [showDashboard, setShowDashboard] = useState(false);
  const [user, setUser] = useState<UserProfile | null>(null);
  const { t, toggleLanguage, language } = useLanguage();
  const [isDark, setIsDark] = useState(false);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 10);
    window.addEventListener('scroll', handleScroll);

    const savedTheme = localStorage.getItem('theme');
    if (savedTheme === 'dark') {
      setIsDark(true);
      document.documentElement.classList.add('dark');
    }

    const currentFileStr = localStorage.getItem('currentFile');
    if (currentFileStr) {
      try { setUser(JSON.parse(currentFileStr)); } catch (e) {}
    }
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const handleLogin = (loggedInUser: UserProfile) => {
    setUser(loggedInUser);
    setShowAuthModal(false);
    setShowDashboard(true);
  };

  const handleLogout = () => {
    setUser(null);
    setShowDashboard(false);
    localStorage.removeItem('currentFile');
  };

  const toggleTheme = () => {
    const nextTheme = !isDark;
    setIsDark(nextTheme);
    document.documentElement.classList.toggle('dark');
    localStorage.setItem('theme', nextTheme ? 'dark' : 'light');
  };

  return (
    <>
      <header className={`fixed top-4 left-1/2 -translate-x-1/2 z-50 flex items-center transition-all duration-500 rounded-full border border-white/20 shadow-lg px-2 gap-2 h-[42px] min-w-[300px] justify-between
        ${isScrolled ? 'backdrop-blur-md bg-white/70 dark:bg-black/50 border-gold/30' : 'backdrop-blur-sm bg-black/20'}`}>

        {/* User Part */}
        <div className="flex items-center">
             {user ? (
               <button onClick={() => setShowDashboard(true)} className="flex items-center justify-center w-8 h-8 rounded-full bg-gold/20 text-gold hover:bg-gold/40 transition-all">
                 <User size={16} />
               </button>
             ) : (
               <button onClick={() => setShowAuthModal(true)} className={`px-2.5 py-1 rounded-full text-[9px] font-bold whitespace-nowrap transition-all ${isScrolled ? 'bg-brand text-gold' : 'bg-white text-brand'}`}>
                 {t('login_register')}
               </button>
             )}
        </div>

        {/* Logo Part - Minimalist */}
        <a href="/" onClick={(e) => { e.preventDefault(); window.scrollTo({top:0, behavior:'smooth'}); }} className="flex-1 flex justify-center px-2">
          <Logo className="h-6" variant={isScrolled ? 'default' : 'white'} />
        </a>

        {/* Controls Part */}
        <div className="flex items-center gap-0.5">
          <button onClick={toggleLanguage} className={`w-7 h-7 flex items-center justify-center font-bold text-[9px] rounded-full hover:bg-white/10 ${isScrolled ? 'text-brand dark:text-gold' : 'text-white'}`}>
            {language === 'ar' ? 'EN' : 'ع'}
          </button>
          <button onClick={toggleTheme} className={`w-7 h-7 flex items-center justify-center rounded-full hover:bg-white/10 ${isScrolled ? 'text-brand dark:text-gold' : 'text-white'}`}>
            {isDark ? <Sun size={14} /> : <Moon size={14} />}
          </button>
          <button onClick={() => setIsMenuOpen(true)} className={`w-7 h-7 flex items-center justify-center rounded-full hover:bg-white/10 ${isScrolled ? 'text-brand dark:text-gold' : 'text-white'}`}>
            <Menu size={18} />
          </button>
        </div>
      </header>

      <SideMenu isOpen={isMenuOpen} onClose={() => setIsMenuOpen(false)} />
      {showAuthModal && <AuthModal onClose={() => setShowAuthModal(false)} onLogin={handleLogin} />}
      {showDashboard && user && <CustomerDashboard user={user} onClose={() => setShowDashboard(false)} onLogout={handleLogout} />}
    </>
  );
};

export default Header;

