    e.preventDefault();
    setLoading(true);
    setTimeout(() => {
      setLoading(false);
      setSubmitted(true);
    }, 1500);
  };

  if (submitted) {
    return (
      <div className="bg-green-50 border border-green-200 rounded-[24px] p-8 text-center animate-in zoom-in duration-300 w-full">
        <CheckCircle2 className="text-green-600 mx-auto mb-4" size={48} />
        <h3 className="text-[18px] font-extrabold text-brand mb-2">تم استلام طلبك لـ {subServiceName}</h3>
        <p className="text-[13px] text-muted leading-relaxed">سيقوم مستشارنا في قطاع ({serviceType}) بالتواصل معك قريباً.</p>
        <Button className="mt-6 w-full" onClick={() => setSubmitted(false)}>طلب خدمة أخرى</Button>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-[24px] border border-gold/30 p-5 shadow-sm w-full">
      <div className="flex items-center gap-3 mb-6">
        <div className="w-12 h-12 rounded-full bg-gold/10 flex items-center justify-center text-gold">
          <Send size={24} />
        </div>
        <div>
          <h3 className="text-[16px] font-extrabold text-brand">طلب {subServiceName}</h3>
          <p className="text-[11px] text-muted">بياناتك محمية ومشفرة SSL</p>
        </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="grid grid-cols-1 gap-4">
          <div className="space-y-1.5">
            <label className="text-[11px] font-bold text-brand block pr-1">الاسم الكامل</label>
            <input required type="text" className="w-full p-3 rounded-[14px] border border-gray-100 bg-gray-50 text-[13px] outline-none focus:border-gold focus:bg-white transition-all" placeholder="أدخل اسمك كما في الهوية" />
          </div>
          <div className="space-y-1.5">
            <label className="text-[11px] font-bold text-brand block pr-1">رقم الجوال</label>
            <input required type="tel" className="w-full p-3 rounded-[14px] border border-gray-100 bg-gray-50 text-[13px] outline-none focus:border-gold focus:bg-white transition-all text-right dir-ltr" placeholder="05xxxxxxxx" />
          </div>
        </div>
        <div className="space-y-1.5">
          <label className="text-[11px] font-bold text-brand block pr-1">تفاصيل إضافية</label>
          <textarea className="w-full p-3 rounded-[14px] border border-gray-100 bg-gray-50 text-[13px] outline-none focus:border-gold focus:bg-white transition-all h-24 resize-none" placeholder="يرجى كتابة لمحة سريعة..."></textarea>
        </div>

        <Button disabled={loading} className="w-full h-12 gap-2 text-[14px] shadow-lg group">
          {loading ? "جاري الإرسال..." : "إرسال طلب الخدمة"}
          {!loading && <ArrowLeft size={16} className="group-hover:-translate-x-1 transition-transform" />}
        </Button>
      </form>
    </div>
  );
};

