      <div className="space-y-8 w-full max-w-full">
        {/* Main Category Intro */}
        <div className="flex flex-col gap-4 bg-gradient-to-br from-brand/5 to-gold/5 p-5 rounded-[24px] border border-gold/10 w-full overflow-hidden">
