                </div>
                <p className="text-[11px] text-muted line-clamp-2 leading-5">{sub.description}</p>
              </button>
            ))}
          </div>
        </div>

        {/* Selected Sub-service Content & Form */}
        {selectedSubService && (
          <div className="animate-in fade-in slide-in-from-bottom-6 duration-500 space-y-6 w-full max-w-full overflow-hidden">
            <Card className="bg-brand text-white border-none shadow-xl !p-6 relative overflow-hidden w-full">
