const HowItWorksSection = () => {
  const { t, direction } = useLanguage();
  const [activeIndex, setActiveIndex] = useState(0);
  const [isPaused, setIsPaused] = useState(false);

  const steps = [
    { 
      title: t('step_1_title'), 
      text: t('step_1_text'),
      image: "https://images.unsplash.com/photo-1554224155-8d04cb21cd6c?auto=format&fit=crop&q=80&w=600",
      step: "01"
    },
    { 
      title: t('step_2_title'), 
      text: t('step_2_text'),
      image: "https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&q=80&w=600",
      step: "02"
    },
    { 
      title: t('step_3_title'), 
      text: t('step_3_text'),
      image: "https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?auto=format&fit=crop&q=80&w=600",
      step: "03"
    },
    { 
      title: t('step_4_title'), 
      text: t('step_4_text'),
      image: "https://images.unsplash.com/photo-1450101499163-c8848c66ca85?auto=format&fit=crop&q=80&w=600",
      step: "04"
    },
  ];

  const nextSlide = useCallback(() => {
    setActiveIndex((prev) => (prev + 1) % steps.length);
  }, [steps.length]);

  const prevSlide = useCallback(() => {
    setActiveIndex((prev) => (prev - 1 + steps.length) % steps.length);
  }, [steps.length]);

  useEffect(() => {
    if (isPaused) return;
    const timer = setInterval(nextSlide, 4500);
    return () => clearInterval(timer);
  }, [nextSlide, isPaused]);

  return (
    <Section id="how-it-works" className="relative">
      <SectionHeader 
        eyebrow={t('how_eyebrow')} 
        title={t('how_title')} 
        subtitle={t('how_subtitle')}
      />

      <div 
        className="relative w-full h-[400px] rounded-[28px] overflow-hidden shadow-2xl group"
        onMouseEnter={() => setIsPaused(true)}
        onMouseLeave={() => setIsPaused(false)}
      >
        {/* Slides Container */}
        <div 
          className="flex h-full w-full transition-transform duration-1000 cubic-bezier(0.4, 0, 0.2, 1)"
          style={{ transform: `translateX(${direction === 'rtl' ? activeIndex * 100 : -activeIndex * 100}%)` }}
        >
          {steps.map((step, i) => (
            <div key={i} className="min-w-full h-full relative">
              {/* Background Image with Parallax-like effect */}
              <img 
                src={step.image} 
                alt={step.title}
                className="absolute inset-0 w-full h-full object-cover transition-transform duration-[5000ms] ease-linear"
                style={{ transform: activeIndex === i ? 'scale(1.15)' : 'scale(1)' }}
              />

              {/* Dynamic Gradient Overlay */}
              <div className="absolute inset-0 bg-gradient-to-t from-brand via-brand/60 to-transparent opacity-90 transition-opacity duration-500"></div>

              {/* Content Overlay */}
              <div className="absolute inset-0 p-8 flex flex-col justify-end text-white">
                {/* Step Counter Badge */}
                <div className="absolute top-6 left-6 w-14 h-14 rounded-2xl border border-white/30 flex items-center justify-center backdrop-blur-xl bg-white/10 shadow-xl transform transition-transform duration-700 hover:rotate-12">
                  <span className="text-[22px] font-black text-gold drop-shadow-md">{step.step}</span>
                </div>

                <div className={`transform transition-all duration-700 ${activeIndex === i ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0'}`}>
                  <div className="inline-block px-3 py-1 rounded-full bg-gold/20 border border-gold/30 text-gold text-[10px] font-bold mb-3 tracking-widest uppercase">
                    {t('how_eyebrow')}
                  </div>
                  <h3 className="text-[24px] font-extrabold mb-3 leading-tight text-white drop-shadow-sm">
                    {step.title}
                  </h3>
                  <p className="text-[14px] text-gray-200 leading-7 opacity-90 max-w-[400px]">
                    {step.text}
                  </p>
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Navigation Arrows (Hidden on mobile by default, shown on hover) */}
        <button 
          onClick={prevSlide}
          className="absolute top-1/2 right-4 -translate-y-1/2 w-10 h-10 rounded-full bg-white/10 backdrop-blur-md border border-white/20 flex items-center justify-center text-white opacity-0 group-hover:opacity-100 transition-all hover:bg-gold hover:text-brand z-20"
        >
          {direction === 'rtl' ? <ChevronRight size={24} /> : <ChevronLeft size={24} />}
        </button>
        <button 
          onClick={nextSlide}
          className="absolute top-1/2 left-4 -translate-y-1/2 w-10 h-10 rounded-full bg-white/10 backdrop-blur-md border border-white/20 flex items-center justify-center text-white opacity-0 group-hover:opacity-100 transition-all hover:bg-gold hover:text-brand z-20"
        >
          {direction === 'rtl' ? <ChevronLeft size={24} /> : <ChevronRight size={24} />}
        </button>

        {/* Progress Bar Indicators */}
        <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-2 z-20">
          {steps.map((_, i) => (
            <button
              key={i}
              onClick={() => setActiveIndex(i)}
              className="group relative h-1.5 transition-all duration-500 rounded-full overflow-hidden bg-white/20"
              style={{ width: activeIndex === i ? '40px' : '12px' }}
            >
              <div 
                className={`h-full bg-gold transition-all duration-[4500ms] ease-linear ${activeIndex === i && !isPaused ? 'w-full' : 'w-0'}`}
              />
            </button>
          ))}
        </div>
      </div>
    </Section>
  );
};

